import{_ as e,c as s,o as t,ag as i}from"./chunks/framework.CgegSSb6.js";const u=JSON.parse('{"title":"User data locations","description":"","frontmatter":{},"headers":[],"relativePath":"articles/user-data-locations.md","filePath":"articles/user-data-locations.md"}'),n={name:"articles/user-data-locations.md"};function o(l,a,p,c,r,d){return t(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="user-data-locations" tabindex="-1">User data locations <a class="header-anchor" href="#user-data-locations" aria-label="Permalink to &quot;User data locations&quot;">​</a></h1><p>Robocode Tank Royale stores preferences, settings, and recordings in platform-specific user data directories.</p><h2 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to &quot;Windows&quot;">​</a></h2><p>On Windows, the user data directory is:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%LOCALAPPDATA%\\Robocode Tank Royale</span></span></code></pre></div><p>This typically expands to:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>C:\\Users\\{YourUsername}\\AppData\\Local\\Robocode Tank Royale</span></span></code></pre></div><p>To open it:</p><ol><li>Press <code>Win + R</code></li><li>Enter <code>%LOCALAPPDATA%\\Robocode Tank Royale</code></li><li>Press Enter</li></ol><p>If <code>%LOCALAPPDATA%</code> is not set, the directory falls back to:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%APPDATA%\\Robocode Tank Royale</span></span></code></pre></div><h2 id="macos" tabindex="-1">macOS <a class="header-anchor" href="#macos" aria-label="Permalink to &quot;macOS&quot;">​</a></h2><p>On macOS, the user data directory is:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/Library/Application Support/Robocode Tank Royale</span></span></code></pre></div><p>To open it:</p><ol><li>Open Finder</li><li>Press <code>Cmd + Shift + G</code></li><li>Enter <code>~/Library/Application Support/Robocode Tank Royale</code></li><li>Press Enter</li></ol><h2 id="linux" tabindex="-1">Linux <a class="header-anchor" href="#linux" aria-label="Permalink to &quot;Linux&quot;">​</a></h2><p>On Linux, the user data directory is:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.config/robocode-tank-royale</span></span></code></pre></div><p>If <code>XDG_CONFIG_HOME</code> is set, the directory becomes:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$XDG_CONFIG_HOME/robocode-tank-royale</span></span></code></pre></div><p>To open it from a terminal:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/robocode-tank-royale</span></span></code></pre></div><h2 id="directory-structure" tabindex="-1">Directory structure <a class="header-anchor" href="#directory-structure" aria-label="Permalink to &quot;Directory structure&quot;">​</a></h2><p>The user data directory contains:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Robocode Tank Royale/</span></span>
<span class="line"><span>├── gui.properties</span></span>
<span class="line"><span>├── server.properties</span></span>
<span class="line"><span>├── game-setups.properties</span></span>
<span class="line"><span>└── recordings/</span></span>
<span class="line"><span>    ├── game-2026-01-23-10-30-45.battle.gz</span></span>
<span class="line"><span>    ├── game-2026-01-23-11-15-20.battle.gz</span></span>
<span class="line"><span>    └── ...</span></span></code></pre></div><p>For the meaning of the configuration files, see <a href="./configuration-files.html">Configuration files</a>.</p><h2 id="recordings-directory" tabindex="-1">Recordings directory <a class="header-anchor" href="#recordings-directory" aria-label="Permalink to &quot;Recordings directory&quot;">​</a></h2><p>The <code>recordings</code> subdirectory stores battle recordings created by the GUI.</p><p>Recording files follow this naming pattern:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>game-{YYYY-MM-DD}-{HH-mm-ss}.battle.gz</span></span></code></pre></div><p>The files:</p><ul><li>use gzip compression</li><li>contain NDJSON data</li><li>can be replayed from <strong>Battle → Replay from File...</strong></li></ul><p>Recordings can accumulate over time, so delete old files manually when you no longer need them.</p>`,34)])])}const g=e(n,[["render",o]]);export{u as __pageData,g as default};
